from llama_stack.tools import ToolRegistry

tool_scopes = {
    'send_email': ['user'],
    'delete_user': ['admin'],
    'query_financials': ['premium']
}

class ScopedToolRegistry(ToolRegistry):
    def invoke_tool(self, tool_name: str, context: dict):
        required_scopes = tool_scopes.get(tool_name, ['user'])
        user_scopes = context.get('user_scopes', [])

        if not any(scope in user_scopes for scope in required_scopes):
            raise PermissionError(f'{tool_name} requires {required_scopes}')

        return super().invoke_tool(tool_name, context)

agent.tool_registry = ScopedToolRegistry()

from llama_stack.memory import MemoryBank
import uuid

class AuthenticatedMemory(MemoryBank):
    def __init__(self):
        self.conversation_scopes = {}

    def store(self, key: str, value: str, context: dict):
        conv_id = context.get('conversation_id', str(uuid.uuid4()))
        self.conversation_scopes.setdefault(conv_id, {})[key] = value

    def retrieve(self, key: str, context: dict):
        conv_id = context.get('conversation_id')
        if conv_id not in self.conversation_scopes:
            raise PermissionError('No conversation context')

        return self.conversation_scopes[conv_id].get(key)

agent.memory = AuthenticatedMemory()
